// src/features/claude-code-mcp-loader/env-expander.ts
function expandEnvVars(value, options = {}) {
  const { trusted = false } = options;
  return value.replace(/\$\{([^}:]+)(?::-([^}]*))?\}/g, (_, varName, defaultValue) => {
    if (!trusted && !isAllowedMcpEnvVar(varName)) {
      const isSensitive = isSensitiveMcpEnvVar(varName);
      const reason = isSensitive ? "sensitive variable" : "not in allowlist";
      log(`Blocked MCP env var expansion for ${reason} "${varName}"`, {
        varName,
        sensitive: isSensitive
      });
      if (defaultValue !== undefined)
        return defaultValue;
      return "";
    }
    const envValue = process.env[varName];
    if (envValue !== undefined)
      return envValue;
    if (defaultValue !== undefined)
      return defaultValue;
    return "";
  });
}
function expandEnvVarsInObject(obj, options = {}) {
  if (obj == null)
    return obj;
  if (typeof obj === "string")
    return expandEnvVars(obj, options);
  if (Array.isArray(obj)) {
    return obj.map((item) => expandEnvVarsInObject(item, options));
  }
  if (typeof obj === "object") {
    const result = {};
    for (const [key, value] of Object.entries(obj)) {
      result[key] = expandEnvVarsInObject(value, options);
    }
    return result;
  }
  return obj;
}

// src/features/claude-code-mcp-loader/scope-filter.ts
