// src/hooks/session-notification-sender.ts
import { platform } from "os";

// src/hooks/session-notification-utils.ts
init_logger();
async function findCommand(commandName) {
  try {
    return Bun.which(commandName);
  } catch (error) {
    log("[session-notification] failed to resolve command path", {
      commandName,
      error: error instanceof Error ? error.message : String(error)
    });
    return null;
  }
}
function logBackgroundCheckError(commandName, error) {
  log("[session-notification] background command check failed", {
    commandName,
    error: error instanceof Error ? error.message : String(error)
  });
}
function createCommandFinder(commandName) {
  let cachedPath = null;
  let pending = null;
  return async () => {
    if (cachedPath !== null)
      return cachedPath;
    if (pending)
      return pending;
    pending = (async () => {
      const path7 = await findCommand(commandName);
      cachedPath = path7;
      return path7;
    })();
    return pending;
  };
}
var getNotifySendPath = createCommandFinder("notify-send");
var getOsascriptPath = createCommandFinder("osascript");
var getPowershellPath = createCommandFinder("powershell");
var getAfplayPath = createCommandFinder("afplay");
var getPaplayPath = createCommandFinder("paplay");
var getAplayPath = createCommandFinder("aplay");
var getTerminalNotifierPath = createCommandFinder("terminal-notifier");
function startBackgroundCheck2(platform) {
  if (platform === "darwin") {
    getOsascriptPath().catch((error) => {
      logBackgroundCheckError("osascript", error);
    });
    getAfplayPath().catch((error) => {
      logBackgroundCheckError("afplay", error);
    });
    getTerminalNotifierPath().catch((error) => {
      logBackgroundCheckError("terminal-notifier", error);
    });
  } else if (platform === "linux") {
    getNotifySendPath().catch((error) => {
      logBackgroundCheckError("notify-send", error);
    });
    getPaplayPath().catch((error) => {
      logBackgroundCheckError("paplay", error);
    });
    getAplayPath().catch((error) => {
      logBackgroundCheckError("aplay", error);
    });
  } else if (platform === "win32") {
    getPowershellPath().catch((error) => {
      logBackgroundCheckError("powershell", error);
    });
  }
}

