// src/hooks/anthropic-context-window-limit-recovery/recovery-hook.ts
init_logger();
function createRecoveryState() {
  return {
    pendingCompact: new Set,
    errorDataBySession: new Map,
    retryStateBySession: new Map,
    retryTimerBySession: new Map,
    truncateStateBySession: new Map,
    emptyContentAttemptBySession: new Map,
    compactionInProgress: new Set
  };
}
function createAnthropicContextWindowLimitRecoveryHook(ctx, options) {
  const autoCompactState = createRecoveryState();
  const experimental = options?.experimental;
  const pluginConfig = options?.pluginConfig ?? {};
  const dependencies = {
    executeCompact,
    getLastAssistant,
    log,
    parseAnthropicTokenLimitError,
    ...options?.dependencies
  };
  const pendingCompactionTimeoutBySession = new Map;
  const eventHandler = async ({ event }) => {
    const props = event.properties;
    if (event.type === "session.deleted") {
      const sessionInfo = props?.info;
      if (sessionInfo?.id) {
        clearSessionTimeout(pendingCompactionTimeoutBySession, sessionInfo.id);
        clearSessionState(autoCompactState, sessionInfo.id);
      }
      return;
    }
    if (event.type === "session.error") {
      const sessionID = props?.sessionID;
      dependencies.log("[auto-compact] session.error received", { sessionID, error: props?.error });
      if (!sessionID)
        return;
      const parsed = dependencies.parseAnthropicTokenLimitError(props?.error);
      dependencies.log("[auto-compact] parsed result", { parsed, hasError: !!props?.error });
      if (parsed) {
        autoCompactState.pendingCompact.add(sessionID);
        autoCompactState.errorDataBySession.set(sessionID, parsed);
        if (autoCompactState.compactionInProgress.has(sessionID)) {
          await attemptDeduplicationRecovery(sessionID, parsed, experimental, ctx.client);
          return;
        }
        const lastAssistant = await dependencies.getLastAssistant(sessionID, ctx.client, ctx.directory);
        const lastAssistantInfo = lastAssistant?.info;
        const providerID = parsed.providerID ?? lastAssistantInfo?.providerID;
        const modelID = parsed.modelID ?? lastAssistantInfo?.modelID;
        await ctx.client.tui.showToast({
          body: {
            title: "Context Limit Hit",
            message: "Truncating large tool outputs and recovering...",
            variant: "warning",
            duration: 3000
          }
        }).catch(() => {});
        clearSessionTimeout(pendingCompactionTimeoutBySession, sessionID);
        const timeoutID = setTimeout(() => {
          pendingCompactionTimeoutBySession.delete(sessionID);
          dependencies.executeCompact(sessionID, { providerID, modelID }, autoCompactState, ctx.client, ctx.directory, pluginConfig, experimental);
        }, 300);
        pendingCompactionTimeoutBySession.set(sessionID, timeoutID);
      }
      return;
    }
    if (event.type === "message.updated") {
      const info = props?.info;
      const sessionID = info?.sessionID;
      if (sessionID && info?.role === "assistant" && info.error) {
        dependencies.log("[auto-compact] message.updated with error", { sessionID, error: info.error });
        const parsed = dependencies.parseAnthropicTokenLimitError(info.error);
        dependencies.log("[auto-compact] message.updated parsed result", { parsed });
        if (parsed) {
          parsed.providerID = info.providerID;
          parsed.modelID = info.modelID;
          autoCompactState.pendingCompact.add(sessionID);
          autoCompactState.errorDataBySession.set(sessionID, parsed);
        }
      }
      return;
    }
    if (event.type === "session.idle") {
      const sessionID = props?.sessionID;
      if (!sessionID)
        return;
      if (!autoCompactState.pendingCompact.has(sessionID))
        return;
      clearSessionTimeout(pendingCompactionTimeoutBySession, sessionID);
      const errorData = autoCompactState.errorDataBySession.get(sessionID);
      const lastAssistant = await dependencies.getLastAssistant(sessionID, ctx.client, ctx.directory);
      const lastAssistantInfo = lastAssistant?.info;
      if (lastAssistantInfo?.summary === true && lastAssistant?.hasContent) {
        clearSessionState(autoCompactState, sessionID);
        return;
      }
      const providerID = errorData?.providerID ?? lastAssistantInfo?.providerID;
      const modelID = errorData?.modelID ?? lastAssistantInfo?.modelID;
      await ctx.client.tui.showToast({
        body: {
          title: "Auto Compact",
          message: "Token limit exceeded. Attempting recovery...",
          variant: "warning",
          duration: 3000
        }
      }).catch(() => {});
      await dependencies.executeCompact(sessionID, { providerID, modelID }, autoCompactState, ctx.client, ctx.directory, pluginConfig, experimental);
    }
  };
  return {
    event: eventHandler,
    dispose: () => {
      clearAllSessionTimeouts(pendingCompactionTimeoutBySession);
      clearAllSessionTimeouts(autoCompactState.retryTimerBySession);
    }
  };
}
