// src/hooks/atlas/recent-model-resolver.ts
async function resolveRecentPromptContextForSession(ctx, sessionID) {
  try {
    const messagesResp = await ctx.client.session.messages({ path: { id: sessionID } });
    const messages = normalizeSDKResponse(messagesResp, []).sort((left, right) => {
      const leftTime = left.info?.time?.created ?? Number.NEGATIVE_INFINITY;
      const rightTime = right.info?.time?.created ?? Number.NEGATIVE_INFINITY;
      if (leftTime !== rightTime)
        return rightTime - leftTime;
      const leftId = typeof left.id === "string" ? left.id : "";
      const rightId = typeof right.id === "string" ? right.id : "";
      return rightId.localeCompare(leftId);
    });
    for (const message of messages) {
      const info = message.info;
      const model2 = info?.model;
      const tools2 = normalizePromptTools(info?.tools);
      if (model2?.providerID && model2?.modelID) {
        return {
          model: {
            providerID: model2.providerID,
            modelID: model2.modelID,
            ...model2.variant ? { variant: model2.variant } : {}
          },
          tools: tools2
        };
      }
      if (info?.providerID && info?.modelID) {
        return { model: { providerID: info.providerID, modelID: info.modelID }, tools: tools2 };
      }
    }
  } catch {}
  let currentMessage = null;
  if (isSqliteBackend()) {
    currentMessage = await findNearestMessageWithFieldsFromSDK(ctx.client, sessionID);
  } else {
    const messageDir = getMessageDir(sessionID);
    currentMessage = messageDir ? findNearestMessageWithFields(messageDir) : null;
  }
  const model = currentMessage?.model;
  const tools = normalizePromptTools(currentMessage?.tools);
  if (!model?.providerID || !model?.modelID) {
    return { tools };
  }
  return {
    model: {
      providerID: model.providerID,
      modelID: model.modelID,
      ...model.variant ? { variant: model.variant } : {}
    },
    tools
  };
}

// src/hooks/atlas/boulder-continuation-injector.ts
async function injectBoulderContinuation(input) {
  const {
    ctx,
    sessionID,
    planName,
    remaining,
    total,
    agent,
    worktreePath,
    preferredTaskSessionId,
    preferredTaskTitle,
    backgroundManager,
    sessionState
  } = input;
  const hasRunningBgTasks = backgroundManager ? backgroundManager.getTasksByParentSession(sessionID).some((t) => t.status === "running") : false;
  if (hasRunningBgTasks) {
    log(`[${HOOK_NAME7}] Skipped injection: background tasks running`, { sessionID });
    return "skipped_background_tasks";
  }
  const worktreeContext = worktreePath ? `

[Worktree: ${worktreePath}]` : "";
  const preferredSessionContext = preferredTaskSessionId ? `

[Preferred reuse session for current top-level plan task${preferredTaskTitle ? `: ${preferredTaskTitle}` : ""}: ${preferredTaskSessionId}]` : "";
  const prompt = BOULDER_CONTINUATION_PROMPT.replace(/{PLAN_NAME}/g, planName) + `

[Status: ${total - remaining}/${total} completed, ${remaining} remaining]` + preferredSessionContext + worktreeContext;
  const continuationAgent = resolveRegisteredAgentName(agent ?? (isAgentRegistered("atlas") ? "atlas" : undefined));
  if (!continuationAgent || !isAgentRegistered(continuationAgent)) {
    log(`[${HOOK_NAME7}] Skipped injection: continuation agent unavailable`, {
      sessionID,
      agent: continuationAgent ?? agent ?? "unknown"
    });
    return "skipped_agent_unavailable";
  }
  try {
    log(`[${HOOK_NAME7}] Injecting boulder continuation`, { sessionID, planName, remaining });
    const promptContext = await resolveRecentPromptContextForSession(ctx, sessionID);
    const inheritedTools = resolveInheritedPromptTools(sessionID, promptContext.tools);
    const launchModel = promptContext.model ? { providerID: promptContext.model.providerID, modelID: promptContext.model.modelID } : undefined;
    const launchVariant = promptContext.model?.variant;
    await ctx.client.session.promptAsync({
      path: { id: sessionID },
      body: {
        agent: continuationAgent,
        ...launchModel ? { model: launchModel } : {},
        ...launchVariant ? { variant: launchVariant } : {},
        ...inheritedTools ? { tools: inheritedTools } : {},
        parts: [createInternalAgentTextPart(prompt)]
      },
      query: { directory: ctx.directory }
    });
    sessionState.promptFailureCount = 0;
    log(`[${HOOK_NAME7}] Boulder continuation injected`, { sessionID });
    return "injected";
  } catch (err) {
    sessionState.promptFailureCount += 1;
    sessionState.lastFailureAt = Date.now();
    log(`[${HOOK_NAME7}] Boulder continuation failed`, {
      sessionID,
      error: String(err),
      promptFailureCount: sessionState.promptFailureCount
    });
    return "failed";
  }
}

// src/hooks/atlas/resolve-active-boulder-session.ts
async function resolveActiveBoulderSession(input) {
  const boulderState = readBoulderState(input.directory);
  if (!boulderState) {
    return null;
  }
  if (!boulderState.session_ids.includes(input.sessionID)) {
    return null;
  }
  const progress = getPlanProgress(boulderState.active_plan);
  if (progress.isComplete) {
    return { boulderState, progress, appendedSession: false };
  }
  return { boulderState, progress, appendedSession: false };
}

// src/hooks/atlas/idle-event.ts
var CONTINUATION_COOLDOWN_MS2 = 5000;
var FAILURE_BACKOFF_MS = 5 * 60 * 1000;
var MAX_CONSECUTIVE_PROMPT_FAILURES = 10;
var RETRY_DELAY_MS = CONTINUATION_COOLDOWN_MS2 + 1000;
