import { existsSync as existsSync62, readFileSync as readFileSync48 } from "fs";
var TODO_HEADING_PATTERN3 = /^##\s+TODOs\b/i;
var FINAL_VERIFICATION_HEADING_PATTERN3 = /^##\s+Final Verification Wave\b/i;
var SECOND_LEVEL_HEADING_PATTERN3 = /^##\s+/;
var UNCHECKED_CHECKBOX_PATTERN3 = /^\s*[-*]\s*\[\s*\]\s*(.+)$/;
var TODO_TASK_PATTERN3 = /^\d+\./;
var FINAL_WAVE_TASK_PATTERN3 = /^F\d+\./i;
function readFinalWavePlanState(planPath) {
  if (!existsSync62(planPath)) {
    return null;
  }
  try {
    const content = readFileSync48(planPath, "utf-8");
    const lines = content.split(/\r?\n/);
    let section = "other";
    let pendingImplementationTaskCount = 0;
    let pendingFinalWaveTaskCount = 0;
    for (const line of lines) {
      if (SECOND_LEVEL_HEADING_PATTERN3.test(line)) {
        section = TODO_HEADING_PATTERN3.test(line) ? "todo" : FINAL_VERIFICATION_HEADING_PATTERN3.test(line) ? "final-wave" : "other";
      }
      const uncheckedTaskMatch = line.match(UNCHECKED_CHECKBOX_PATTERN3);
      if (!uncheckedTaskMatch) {
        continue;
      }
      const taskLabel = uncheckedTaskMatch[1].trim();
      if (section === "todo" && TODO_TASK_PATTERN3.test(taskLabel)) {
        pendingImplementationTaskCount += 1;
      }
      if (section === "final-wave" && FINAL_WAVE_TASK_PATTERN3.test(taskLabel)) {
        pendingFinalWaveTaskCount += 1;
      }
    }
    return {
      pendingImplementationTaskCount,
      pendingFinalWaveTaskCount
    };
  } catch {
    return null;
  }
}

// src/hooks/atlas/final-wave-approval-gate.ts
var APPROVE_VERDICT_PATTERN = /\bVERDICT:\s*APPROVE\b/i;
function clearFinalWaveApprovalTracking(sessionState) {
  sessionState.pendingFinalWaveTaskCount = undefined;
  sessionState.approvedFinalWaveTaskCount = undefined;
}
function shouldPauseForFinalWaveApproval(input) {
  const planState = readFinalWavePlanState(input.planPath);
  if (!planState) {
    return false;
  }
  if (planState.pendingImplementationTaskCount > 0 || planState.pendingFinalWaveTaskCount === 0) {
    clearFinalWaveApprovalTracking(input.sessionState);
    return false;
  }
  if (!APPROVE_VERDICT_PATTERN.test(input.taskOutput)) {
    return false;
  }
  if (planState.pendingFinalWaveTaskCount === 1) {
    clearFinalWaveApprovalTracking(input.sessionState);
    return true;
  }
  if (input.sessionState.pendingFinalWaveTaskCount !== planState.pendingFinalWaveTaskCount) {
    input.sessionState.pendingFinalWaveTaskCount = planState.pendingFinalWaveTaskCount;
    input.sessionState.approvedFinalWaveTaskCount = 0;
  }
  input.sessionState.approvedFinalWaveTaskCount = (input.sessionState.approvedFinalWaveTaskCount ?? 0) + 1;
  const shouldPause = input.sessionState.approvedFinalWaveTaskCount >= planState.pendingFinalWaveTaskCount;
  if (shouldPause) {
    clearFinalWaveApprovalTracking(input.sessionState);
  }
  return shouldPause;
}

// src/hooks/atlas/sisyphus-path.ts
