// src/hooks/preemptive-compaction-degradation-monitor.ts
var PREEMPTIVE_COMPACTION_TIMEOUT_MS = 120000;
var POST_COMPACTION_MONITOR_COUNT = 5;
var POST_COMPACTION_NO_TEXT_THRESHOLD = 3;
