  if (tools.length === 0) {
    return;
  }
  sections.push("**Tools:**", "");
  for (const toolDefinition of tools) {
    sections.push(`#### \`${toolDefinition.name}\``);
    if (toolDefinition.description) {
      sections.push(toolDefinition.description);
    }
    sections.push("", "**inputSchema:**", "```json", JSON.stringify(sanitizeJsonSchema(toolDefinition.inputSchema), null, 2), "```", "");
  }
