// src/tools/session-manager/file-storage.ts
import { existsSync as existsSync77 } from "fs";
import { readdir, readFile as readFile2 } from "fs/promises";
import { join as join85 } from "path";
async function getFileMainSessions(directory) {
  if (!existsSync77(SESSION_STORAGE))
    return [];
  const sessions = [];
  try {
    const projectDirs = await readdir(SESSION_STORAGE, { withFileTypes: true });
    for (const projectDir of projectDirs) {
      if (!projectDir.isDirectory())
        continue;
      const projectPath = join85(SESSION_STORAGE, projectDir.name);
      const sessionFiles = await readdir(projectPath);
      for (const file of sessionFiles) {
        if (!file.endsWith(".json"))
          continue;
        try {
          const content = await readFile2(join85(projectPath, file), "utf-8");
          const meta = JSON.parse(content);
          if (meta.parentID)
            continue;
          if (directory && meta.directory !== directory)
            continue;
          sessions.push(meta);
        } catch {
          continue;
        }
      }
    }
  } catch {
    return [];
  }
  return sessions.sort((a, b) => b.time.updated - a.time.updated);
}
async function getFileAllSessions() {
  if (!existsSync77(MESSAGE_STORAGE))
    return [];
  const sessions = [];
  async function scanDirectory(dir) {
    try {
      const entries = await readdir(dir, { withFileTypes: true });
      for (const entry of entries) {
        if (!entry.isDirectory())
          continue;
        const sessionPath = join85(dir, entry.name);
        const files = await readdir(sessionPath);
        if (files.some((file) => file.endsWith(".json"))) {
          sessions.push(entry.name);
          continue;
        }
        await scanDirectory(sessionPath);
      }
    } catch {
      return;
    }
  }
  await scanDirectory(MESSAGE_STORAGE);
  return [...new Set(sessions)];
}
async function fileSessionExists(sessionID) {
  return getMessageDir(sessionID) !== null;
}
async function getFileSessionMessages(sessionID) {
  const messageDir = getMessageDir(sessionID);
  if (!messageDir || !existsSync77(messageDir))
    return [];
  const messages = [];
  try {
    const files = await readdir(messageDir);
    for (const file of files) {
      if (!file.endsWith(".json"))
        continue;
      try {
        const content = await readFile2(join85(messageDir, file), "utf-8");
        const meta = JSON.parse(content);
        const parts = await readParts2(meta.id);
        messages.push({
          id: meta.id,
          role: meta.role,
          agent: meta.agent,
          time: meta.time,
          parts
        });
      } catch {
        continue;
      }
    }
  } catch {
    return [];
  }
  return messages.sort((a, b) => {
    const aTime = a.time?.created ?? 0;
    const bTime = b.time?.created ?? 0;
    if (aTime !== bTime)
      return aTime - bTime;
    return a.id.localeCompare(b.id);
  });
}
async function readParts2(messageID) {
  const partDir = join85(PART_STORAGE, messageID);
  if (!existsSync77(partDir))
    return [];
  const parts = [];
  try {
    const files = await readdir(partDir);
    for (const file of files) {
      if (!file.endsWith(".json"))
        continue;
      try {
        const content = await readFile2(join85(partDir, file), "utf-8");
        parts.push(JSON.parse(content));
      } catch {
        continue;
      }
    }
  } catch {
    return [];
  }
  return parts.sort((a, b) => a.id.localeCompare(b.id));
}
async function getFileSessionTodos(sessionID) {
  if (!existsSync77(TODO_DIR2))
    return [];
  try {
    const allFiles = await readdir(TODO_DIR2);
    const todoFiles = allFiles.filter((file) => file === `${sessionID}.json`);
    for (const file of todoFiles) {
      try {
        const content = await readFile2(join85(TODO_DIR2, file), "utf-8");
        const data = JSON.parse(content);
        if (!Array.isArray(data))
          continue;
        return data.map((item) => ({
          id: item.id || "",
          content: item.content || "",
          status: item.status || "pending",
          priority: item.priority
        }));
      } catch {
        continue;
      }
    }
  } catch {
    return [];
  }
  return [];
}
async function getFileSessionTranscript(sessionID) {
  if (!existsSync77(TRANSCRIPT_DIR2))
    return 0;
  const transcriptFile = join85(TRANSCRIPT_DIR2, `${sessionID}.jsonl`);
  if (!existsSync77(transcriptFile))
    return 0;
  try {
    const content = await readFile2(transcriptFile, "utf-8");
    return content.trim().split(`
`).filter(Boolean).length;
  } catch {
    return 0;
  }
}
async function getFileSessionInfo(sessionID) {
  const messages = await getFileSessionMessages(sessionID);
  if (messages.length === 0)
    return null;
  const agentsUsed = new Set;
  let firstMessage;
  let lastMessage;
  for (const msg of messages) {
    if (msg.agent)
      agentsUsed.add(msg.agent);
    if (!msg.time?.created)
      continue;
    const date = new Date(msg.time.created);
    if (!firstMessage || date < firstMessage)
      firstMessage = date;
    if (!lastMessage || date > lastMessage)
      lastMessage = date;
  }
  const todos = await getFileSessionTodos(sessionID);
  const transcriptEntries = await getFileSessionTranscript(sessionID);
  return {
    id: sessionID,
    message_count: messages.length,
    first_message: firstMessage,
    last_message: lastMessage,
    agents_used: Array.from(agentsUsed),
    has_todos: todos.length > 0,
    has_transcript: transcriptEntries > 0,
    todos,
    transcript_entries: transcriptEntries
  };
}

// src/tools/session-manager/sdk-unavailable.ts
var SDK_UNAVAILABLE_PATTERNS = [
  "unable to connect",
  "econnrefused",
  "fetch failed",
  "network error",
  "network request failed",
  "server unreachable",
  "etimedout",
  "timed out",
  "timeout",
  "socket hang up"
];
function collectErrorTexts(value) {
  if (value instanceof Error) {
    return [value.message, value.name, ...collectErrorTexts(value.cause)];
  }
  if (typeof value === "string") {
    return [value];
  }
  if (!value || typeof value !== "object") {
    return [];
  }
  const record = value;
  return [
    typeof record.message === "string" ? record.message : "",
    typeof record.code === "string" ? record.code : "",
    typeof record.name === "string" ? record.name : "",
    ...collectErrorTexts(record.cause),
    ...collectErrorTexts(record.error)
  ].filter(Boolean);
}
function isSessionSdkUnavailableError(value) {
  const haystack = collectErrorTexts(value).join(" ").toLowerCase();
  return SDK_UNAVAILABLE_PATTERNS.some((pattern) => haystack.includes(pattern));
}

