  lines.push(`Status: ${task.status}`);
  lines.push(`Session ID: ${task.sessionID}`);
  lines.push(`Total messages: ${normalizedMessages.length}`);
  lines.push(`Returned: ${visibleMessages.length}`);
  lines.push(`Has more: ${hasMore ? "true" : "false"}`);
  lines.push("");
