          elapsedMs,
          stableIdlePolls: tracked.stableIdlePolls,
          activityVersion: tracked.activityVersion,
          observedIdleActivityVersion: tracked.observedIdleActivityVersion,
          missingSince,
          missingTooLong,
          isTimedOut,
          shouldCloseViaStability
